using System;

class Program
{
    static void Main(string[] args)
    {
        int[] numbers = { 10, 20, 30, 40, 50 };

        Console.WriteLine("Massivin elementləri:");
        for (int i = 0; i < numbers.Length; i++)
        {
            Console.WriteLine($"Indeks {i}: {numbers[i]}");
        }
    }
}
// Output:
// Massivin elementləri:
// Indeks 0: 10
// Indeks 1: 20
// Indeks 2: 30
// Indeks 3: 40
// Indeks 4: 50

